    dist[0][0] = 0

    val queue = PriorityQueue<Triple<Long, Long, Boolean>>(Comparator { a, b ->
        if (a.first != b.first) a.first.compareTo(b.first)
        else if (a.second != b.second) a.second.compareTo(b.second)
        else a.third.compareTo(b.third)
    })

