            val v = entry.first
            val w = entry.second

            val newCost = cost + w
            if (newCost < dist[v.toInt()][if (used) 1 else 0]) {
                dist[v.toInt()][if (used) 1 else 0] = newCost
                queue.add(Triple(newCost, v, used))
