                    dist[v.toInt()][1] = newCostRev
                    queue.add(Triple(newCostRev, v, true))
                }
            }
        }
    }

    return if (dist[n.toInt() - 1][0] == Int.MAX_VALUE) -1 else dist[n.toInt() - 1][0]
